import{_ as t,c as i,o as s,a1 as n}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Skills aktualisieren: Bleib auf dem neuesten Stand | opencode-openskills","description":"Lerne den OpenSkills update-Befehl, um installierte Skills zu aktualisieren. Unterstützt die Massenaktualisierung aller Skills oder die Angabe bestimmter Skills. Verstehe den Unterschied zwischen lokalen Pfaden und Git-Repository-Updates und halte deine Skills auf dem neuesten Stand.","frontmatter":{"title":"Skills aktualisieren: Bleib auf dem neuesten Stand | opencode-openskills","sidebarTitle":"One-Click Skill-Update","subtitle":"Skills aktualisieren: Bleib auf dem neuesten Stand","description":"Lerne den OpenSkills update-Befehl, um installierte Skills zu aktualisieren. Unterstützt die Massenaktualisierung aller Skills oder die Angabe bestimmter Skills. Verstehe den Unterschied zwischen lokalen Pfaden und Git-Repository-Updates und halte deine Skills auf dem neuesten Stand.","tags":["skills","update","git"],"prerequisite":["start-installation","start-first-skill"],"order":5},"headers":[],"relativePath":"de/numman-ali/openskills/platforms/update-skills/index.md","filePath":"de/numman-ali/openskills/platforms/update-skills/index.md"}'),l={name:"de/numman-ali/openskills/platforms/update-skills/index.md"};function a(r,e,d,o,u,h){return s(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="skills-aktualisieren-immer-synchron-mit-dem-quell-repository" tabindex="-1">Skills aktualisieren: Immer synchron mit dem Quell-Repository <a class="header-anchor" href="#skills-aktualisieren-immer-synchron-mit-dem-quell-repository" aria-label="Permalink to &quot;Skills aktualisieren: Immer synchron mit dem Quell-Repository&quot;">​</a></h1><h2 id="was-du-nach-diesem-tutorial-konnen-wirst" tabindex="-1">Was du nach diesem Tutorial können wirst <a class="header-anchor" href="#was-du-nach-diesem-tutorial-konnen-wirst" aria-label="Permalink to &quot;Was du nach diesem Tutorial können wirst&quot;">​</a></h2><p>In dieser Lektion lernst du, wie du deine OpenSkills-Skills immer auf dem neuesten Stand hältst. Mit dem OpenSkills update-Befehl kannst du:</p><ul><li>Alle installierten Skills mit einem Klick aktualisieren</li><li>Nur bestimmte Skills aktualisieren</li><li>Die Unterschiede bei der Aktualisierung aus verschiedenen Quellen verstehen</li><li>Gründe für fehlgeschlagene Updates erkennen und beheben</li></ul><h2 id="dein-aktuelles-dilemma" tabindex="-1">Dein aktuelles Dilemma <a class="header-anchor" href="#dein-aktuelles-dilemma" aria-label="Permalink to &quot;Dein aktuelles Dilemma&quot;">​</a></h2><p>Skill-Repositories werden ständig aktualisiert – die Autoren beheben Bugs, fügen neue Funktionen hinzu und verbessern die Dokumentation. Aber deine installierten Skills sind noch auf einer alten Version.</p><p>Vielleicht hast du bereits diese Situationen erlebt:</p><ul><li>Die Skill-Dokumentation sagt &quot;unterstützt eine bestimmte Funktion&quot;, aber dein AI-Agent sagt, er kennt sie nicht</li><li>Der Skill hat bessere Fehlermeldungen erhalten, aber du siehst immer noch die alten</li><li>Der Bug, den du beim Installieren hattest, wurde behoben, aber du bist immer noch betroffen</li></ul><p><strong>Jedes Mal löschen und neu installieren ist zu mühsam</strong> – du brauchst einen effizienteren Weg zur Aktualisierung.</p><h2 id="wann-du-diese-funktion-verwenden-solltest" tabindex="-1">Wann du diese Funktion verwenden solltest <a class="header-anchor" href="#wann-du-diese-funktion-verwenden-solltest" aria-label="Permalink to &quot;Wann du diese Funktion verwenden solltest&quot;">​</a></h2><p>Typische Szenarien für die Verwendung des <code>update</code>-Befehls:</p><table tabindex="0"><thead><tr><th>Szenario</th><th>Aktion</th></tr></thead><tbody><tr><td>Entdecke ein Skill-Update</td><td>Führe <code>openskills update</code> aus</td></tr><tr><td>Aktualisiere nur einige Skills</td><td><code>openskills update skill1,skill2</code></td></tr><tr><td>Teste lokal entwickelte Skills</td><td>Aktualisiere vom lokalen Pfad</td></tr><tr><td>Aktualisiere vom GitHub-Repository</td><td>Klone den neuesten Code automatisch</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Empfohlene Aktualisierungsfrequenz</p><ul><li><strong>Community-Skills</strong>: Einmal pro Monat aktualisieren, um die neuesten Verbesserungen zu erhalten</li><li><strong>Selbst entwickelte Skills</strong>: Nach jeder Änderung manuell aktualisieren</li><li><strong>Lokale Pfad-Skills</strong>: Nach jeder Code-Änderung aktualisieren</li></ul></div><h2 id="🎒-vorbereitungen-vor-dem-start" tabindex="-1">🎒 Vorbereitungen vor dem Start <a class="header-anchor" href="#🎒-vorbereitungen-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitungen vor dem Start&quot;">​</a></h2><p>Bevor du beginnst, stelle sicher, dass du folgendes erledigt hast:</p><ul><li>[x] OpenSkills ist installiert (siehe <a href="./../../start/installation/">OpenSkills installieren</a>)</li><li>[x] Mindestens ein Skill ist installiert (siehe <a href="./../../start/first-skill/">Der erste Skill</a>)</li><li>[x] Wenn du von GitHub installiert hast, stelle sicher, dass du eine Internetverbindung hast</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Der Aktualisierungsmechanismus von OpenSkills ist einfach:</p><p><strong>Quellinformationen bei jeder Installation speichern → Beim Aktualisieren vom ursprünglichen Quellort neu kopieren</strong></p><div class="info custom-block"><p class="custom-block-title">Warum muss neu installiert werden?</p><p>Alte Skill-Versionen (installiert, ohne Quellen zu erfassen) können nicht aktualisiert werden. In diesem Fall muss der Skill einmal neu installiert werden. OpenSkills speichert dann die Quelle und kann ihn danach automatisch aktualisieren.</p></div><p><strong>Aktualisierungsmethoden für drei Installationsquellen</strong>:</p><table tabindex="0"><thead><tr><th>Quelltyp</th><th>Aktualisierungsmethode</th><th>Anwendungsszenario</th></tr></thead><tbody><tr><td><strong>Lokaler Pfad</strong></td><td>Direkte Kopie vom lokalen Pfad</td><td>Entwicklung eigener Skills</td></tr><tr><td><strong>Git-Repository</strong></td><td>Klone neuesten Code in temporäres Verzeichnis</td><td>Installation von GitHub/GitLab</td></tr><tr><td><strong>GitHub-Kurzschreibweise</strong></td><td>In vollständige URL konvertieren und klonen</td><td>Installation von offiziellen GitHub-Repositories</td></tr></tbody></table><p>Beim Aktualisieren werden Skills ohne Quell-Metadaten übersprungen, und die Namen der Skills, die neu installiert werden müssen, werden aufgelistet.</p><h2 id="mach-mit" tabindex="-1">Mach mit <a class="header-anchor" href="#mach-mit" aria-label="Permalink to &quot;Mach mit&quot;">​</a></h2><h3 id="schritt-1-installierte-skills-anzeigen" tabindex="-1">Schritt 1: Installierte Skills anzeigen <a class="header-anchor" href="#schritt-1-installierte-skills-anzeigen" aria-label="Permalink to &quot;Schritt 1: Installierte Skills anzeigen&quot;">​</a></h3><p>Bestätige zunächst, welche Skills aktualisiert werden können:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>Du solltest sehen</strong>: Eine Liste der installierten Skills mit Name, Beschreibung und Installationstags (project/global)</p><h3 id="schritt-2-alle-skills-aktualisieren" tabindex="-1">Schritt 2: Alle Skills aktualisieren <a class="header-anchor" href="#schritt-2-alle-skills-aktualisieren" aria-label="Permalink to &quot;Schritt 2: Alle Skills aktualisieren&quot;">​</a></h3><p>Der einfachste Weg ist die Aktualisierung aller installierten Skills:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>Du solltest sehen</strong>: Skills werden nacheinander aktualisiert, jeder Skill zeigt das Aktualisierungsergebnis</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Skipped: my-old-skill (no source metadata; re-install once to enable updates)</span></span>
<span class="line"><span>Summary: 2 updated, 1 skipped (3 total)</span></span></code></pre></div><details class="details custom-block"><summary>Bedeutung von übersprungenen Skills</summary><p>Wenn du <code>Skipped: xxx (no source metadata)</code> siehst, wurde dieser Skill installiert, bevor die Aktualisierungsfunktion hinzugefügt wurde. Du musst ihn einmal neu installieren, um automatische Aktualisierungen zu ermöglichen.</p></details><h3 id="schritt-3-bestimmte-skills-aktualisieren" tabindex="-1">Schritt 3: Bestimmte Skills aktualisieren <a class="header-anchor" href="#schritt-3-bestimmte-skills-aktualisieren" aria-label="Permalink to &quot;Schritt 3: Bestimmte Skills aktualisieren&quot;">​</a></h3><p>Wenn du nur bestimmte Skills aktualisieren möchtest, gib die Skill-Namen an (kommagetrennt):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git-workflow,check-branch-first</span></span></code></pre></div><p><strong>Du solltest sehen</strong>: Nur die beiden angegebenen Skills wurden aktualisiert</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: git-workflow</span></span>
<span class="line"><span>✅ Updated: check-branch-first</span></span>
<span class="line"><span>Summary: 2 updated, 0 skipped (2 total)</span></span></code></pre></div><h3 id="schritt-4-lokal-entwickelte-skills-aktualisieren" tabindex="-1">Schritt 4: Lokal entwickelte Skills aktualisieren <a class="header-anchor" href="#schritt-4-lokal-entwickelte-skills-aktualisieren" aria-label="Permalink to &quot;Schritt 4: Lokal entwickelte Skills aktualisieren&quot;">​</a></h3><p>Wenn du gerade einen Skill lokal entwickelst, kannst du ihn vom lokalen Pfad aktualisieren:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-skill</span></span></code></pre></div><p><strong>Du solltest sehen</strong>: Der Skill wurde vom lokalen Pfad, der während der Installation angegeben wurde, neu kopiert</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Updated: my-skill</span></span>
<span class="line"><span>Summary: 1 updated, 0 skipped (1 total)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Workflow für die lokale Entwicklung</p><p>Entwicklungsprozess:</p><ol><li>Skill installieren: <code>openskills install ./my-skill</code></li><li>Code ändern</li><li>Skill aktualisieren: <code>openskills update my-skill</code></li><li>Mit AGENTS.md synchronisieren: <code>openskills sync</code></li></ol></div><h3 id="schritt-5-fehler-bei-der-aktualisierung-beheben" tabindex="-1">Schritt 5: Fehler bei der Aktualisierung beheben <a class="header-anchor" href="#schritt-5-fehler-bei-der-aktualisierung-beheben" aria-label="Permalink to &quot;Schritt 5: Fehler bei der Aktualisierung beheben&quot;">​</a></h3><p>Wenn bestimmte Skills nicht aktualisiert werden können, zeigt OpenSkills den detaillierten Grund an:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p><strong>Mögliche Situationen, die du sehen könntest</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skipped: git-workflow (git clone failed)</span></span>
<span class="line"><span>Skipped: my-skill (local source missing)</span></span>
<span class="line"><span>Missing source metadata (1): old-skill</span></span>
<span class="line"><span>Clone failed (1): git-workflow</span></span></code></pre></div><p><strong>Entsprechende Lösungen</strong>:</p><table tabindex="0"><thead><tr><th>Fehlermeldung</th><th>Ursache</th><th>Lösung</th></tr></thead><tbody><tr><td><code>no source metadata</code></td><td>Installation alter Version</td><td>Neu installieren: <code>openskills install &lt;source&gt;</code></td></tr><tr><td><code>local source missing</code></td><td>Lokaler Pfad wurde gelöscht</td><td>Wiederherstellung des lokalen Pfads oder Neuinstallation</td></tr><tr><td><code>SKILL.md missing at local source</code></td><td>Lokale Datei wurde gelöscht</td><td>Wiederherstellung der SKILL.md-Datei</td></tr><tr><td><code>git clone failed</code></td><td>Netzwerkproblem oder Repository existiert nicht</td><td>Netzwerkverbindung oder Repository-Adresse prüfen</td></tr><tr><td><code>SKILL.md not found in repo</code></td><td>Repository-Struktur hat sich geändert</td><td>Skill-Autor kontaktieren oder subpath aktualisieren</td></tr></tbody></table><h2 id="prufpunkte-✅" tabindex="-1">Prüfpunkte ✅ <a class="header-anchor" href="#prufpunkte-✅" aria-label="Permalink to &quot;Prüfpunkte ✅&quot;">​</a></h2><p>Stelle sicher, dass du gelernt hast:</p><ul><li>[ ] Wie man mit <code>openskills update</code> alle Skills aktualisiert</li><li>[ ] Wie man bestimmte Skills mit Kommata getrennt aktualisiert</li><li>[ ] Die Bedeutung von &quot;übersprungenen&quot; Skills und deren Lösungen</li><li>[ ] Den Aktualisierungsworkflow für lokal entwickelte Skills</li></ul><h2 id="warnhinweise" tabindex="-1">Warnhinweise <a class="header-anchor" href="#warnhinweise" aria-label="Permalink to &quot;Warnhinweise&quot;">​</a></h2><h3 id="❌-haufige-fehler" tabindex="-1">❌ Häufige Fehler <a class="header-anchor" href="#❌-haufige-fehler" aria-label="Permalink to &quot;❌ Häufige Fehler&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Fehler</th><th>Richtige Vorgehensweise</th></tr></thead><tbody><tr><td>Bei &quot;Skipped&quot; nichts tun</td><td>Nach Hinweis neu installieren oder Problem beheben</td></tr><tr><td>Jedes Mal löschen und neu installieren</td><td><code>update</code>-Befehl ist effizienter</td></tr><tr><td>Nicht wissen, woher der Skill stammt</td><td>Mit <code>openskills list</code> die Quelle anzeigen</td></tr></tbody></table><h3 id="⚠️-wichtige-hinweise" tabindex="-1">⚠️ Wichtige Hinweise <a class="header-anchor" href="#⚠️-wichtige-hinweise" aria-label="Permalink to &quot;⚠️ Wichtige Hinweise&quot;">​</a></h3><p><strong>Aktualisierung überschreibt lokale Änderungen</strong></p><p>Wenn du Dateien direkt im Installationsverzeichnis des Skills geändert hast, werden diese Änderungen bei der Aktualisierung überschrieben. Die richtige Vorgehensweise ist:</p><ol><li>Ändere die <strong>Quelldateien</strong> (lokaler Pfad oder Repository)</li><li>Führe dann <code>openskills update</code> aus</li></ol><p><strong>Symbolische Links erfordern besondere Behandlung</strong></p><p>Wenn der Skill über einen symbolischen Link installiert wurde (siehe <a href="./../../advanced/symlink-support/">Symlink-Unterstützung</a>), wird beim Aktualisieren der Link neu erstellt, ohne die symbolische Link-Beziehung zu zerstören.</p><p><strong>Globale und Projekt-Skills müssen separat aktualisiert werden</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Nur Projekt-Skills aktualisieren (Standard)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Globale Skills müssen separat behandelt werden</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Oder im --universal-Modus für einheitliche Verwaltung verwenden</span></span></code></pre></div><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><p>In dieser Lektion haben wir die Aktualisierungsfunktion von OpenSkills kennengelernt:</p><ul><li><strong>Massenaktualisierung</strong>: <code>openskills update</code> aktualisiert alle Skills mit einem Klick</li><li><strong>Gezielte Aktualisierung</strong>: <code>openskills update skill1,skill2</code> aktualisiert bestimmte Skills</li><li><strong>Quellenerkennung</strong>: Automatische Erkennung von lokalen Pfaden und Git-Repositories</li><li><strong>Fehlermeldungen</strong>: Detaillierte Erläuterung der Gründe für übersprungene Skills und deren Lösungen</li></ul><p>Die Aktualisierungsfunktion hält deine Skills auf der neuesten Version und stellt sicher, dass du immer die neuesten Verbesserungen und Fehlerbehebungen nutzt.</p><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../remove-skills/">Skills entfernen</a></strong>.</p><p>Du wirst lernen:</p><ul><li>Wie man mit dem interaktiven <code>manage</code>-Befehl Skills entfernt</li><li>Wie man mit dem <code>remove</code>-Befehl das Entfernen skriptet</li><li>Was nach dem Entfernen eines Skills zu beachten ist</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcode-Standort anzuzeigen</strong></summary><blockquote><p>Aktualisiert am: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Hauptlogik für Skill-Aktualisierung</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L14-L150" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>14-150</td></tr><tr><td>Aktualisierung vom lokalen Pfad</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L64-L82" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>64-82</td></tr><tr><td>Aktualisierung vom Git-Repository</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L85-L125" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>85-125</td></tr><tr><td>Skill aus Verzeichnis kopieren</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L152-L163" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>152-163</td></tr><tr><td>Pfadsicherheitsvalidierung</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/update.ts#L165-L172" target="_blank" rel="noreferrer"><code>src/commands/update.ts</code></a></td><td>165-172</td></tr><tr><td>Metadaten-Strukturdefinition</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L8-L15" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>8-15</td></tr><tr><td>Skill-Metadaten lesen</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L17-L27" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>17-27</td></tr><tr><td>Skill-Metadaten schreiben</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skill-metadata.ts#L29-L36" target="_blank" rel="noreferrer"><code>src/utils/skill-metadata.ts</code></a></td><td>29-36</td></tr><tr><td>CLI-Befehlsdefinition</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/cli.ts#L58-L62" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>58-62</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>SKILL_METADATA_FILE = &#39;.openskills.json&#39;</code>: Name der Metadatendatei, zeichnet die Installationsquelle des Skills auf</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>updateSkills(skillNames)</code>: Hauptfunktion zum Aktualisieren bestimmter oder aller Skills</li><li><code>updateSkillFromDir(targetPath, sourceDir)</code>: Kopiert Skill vom Quellverzeichnis zum Zielverzeichnis</li><li><code>isPathInside(targetPath, targetDir)</code>: Validiert Installationssicherheit (verhindert Path Traversal)</li><li><code>readSkillMetadata(skillDir)</code>: Liest Metadaten des Skills</li><li><code>writeSkillMetadata(skillDir, metadata)</code>: Schreibt/aktualisiert Metadaten des Skills</li></ul><p><strong>Geschäftsregeln</strong>:</p><ul><li><strong>BR-5-1</strong>: Standardmäßig alle installierten Skills aktualisieren (update.ts:37-38)</li><li><strong>BR-5-2</strong>: Unterstützt kommagetrennte Liste von Skill-Namen (update.ts:15)</li><li><strong>BR-5-3</strong>: Überspringt Skills ohne Quell-Metadaten (update.ts:56-62)</li><li><strong>BR-5-4</strong>: Unterstützt Aktualisierung vom lokalen Pfad (update.ts:64-82)</li><li><strong>BR-5-5</strong>: Unterstützt Aktualisierung vom Git-Repository (update.ts:85-125)</li><li><strong>BR-5-6</strong>: Validiert Pfadsicherheit (update.ts:156-162)</li></ul></details>`,75)])])}const c=t(l,[["render",a]]);export{p as __pageData,c as default};
